13|// ── CDP session ──
14|class CDPSession {
15|  constructor(ws) {
16|    this.ws = ws;
17|    this.id = 0;
18|    this.pending = new Map();
19|  }
20|
21|  static async connect(pageTarget) {
22|    const ws = new WebSocket(pageTarget.webSocketDebuggerUrl);
23|    await new Promise((resolve, reject) => {
24|      ws.on('open', resolve);
25|      ws.on('error', reject);
26|    });
27|    const session = new CDPSession(ws);
28|    ws.on('message', (data) => session._onMessage(data));
29|    return session;
30|  }
31|
32|  _onMessage(data) {
33|    try {
34|      const msg = JSON.parse(data.toString());
35|      if (msg.id && this.pending.has(msg.id)) {
36|        this.pending.get(msg.id)(msg);
37|        this.pending.delete(msg.id);
38|      }
39|    } catch (e) {
40|      console.error('[CDP] Parse error:', e.message);
41|    }
42|  }
43|
44|  async send(method, params = {}) {
45|    const id = ++this.id;
46|    this.ws.send(JSON.stringify({ id, method, params }));
47|    return new Promise((resolve, reject) => {
48|      const timer = setTimeout(() => {
49|        this.pending.delete(id);
50|        reject(new Error(`CDP timeout: ${method}`));
51|      }, 15000);
52|      this.pending.set(id, (msg) => {
53|        clearTimeout(timer);
54|        if (msg.error) reject(new Error(msg.error.message));
55|        else resolve(msg.result);
56|      });
57|    });
58|  }
59|}
