{"content":"#!/usr/bin/env python3
"""Batch Quick Apply script for SEEK via Tandem browser."""
import json, urllib.request, time, sys

API = "http://127.0.0.1:3099"

def evaluate(expression):
    data = json.dumps({"expression": expression}).encode()
    req = urllib.request.Request(f"{API}/evaluate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    resp = json.loads(urllib.request.urlopen(req).read())
    return resp.get("result")

def navigate(url):
    data = json.dumps({"url": url}).encode()
    req = urllib.request.Request(f"{API}/navigate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    urllib.request.urlopen(req)
    time.sleep(3)

def click_text(text):
    data = json.dumps({"text": text}).encode()
    req = urllib.request.Request(f"{API}/click-text", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    return json.loads(urllib.request.urlopen(req).read())

def js_click(button_text):
    """Click a button by its exact text using JavaScript."""
    result = evaluate(f"""
    (() => {{
        const btns = document.querySelectorAll('button, a, [role="button"]');
        for (const btn of btns) {{
            const t = (btn.textContent || btn.value || '').trim();
            if (t === '{button_text}') {{
                btn.scrollIntoView({{block: 'center'}});
                btn.click();
                return 'clicked: ' + t;
            }}
        }}
        // Try fuzzy match
        for (const btn of btns) {{
            const t = (btn.textContent || btn.value || '').trim();
            if (t.toLowerCase().includes('{button_text.lower()}')) {{
                btn.scrollIntoView({{block: 'center'}});
                btn.click();
                return 'clicked_fuzzy: ' + t;
            }}
        }}
        return 'not found: ' + '{button_text}';
    }})()
    """)
    return result

def do_quick_apply(title, url):
    print(f"\n{'='*60}")
    print(f"Applying: {title}")
    print(f"{'='*60}")

    navigate(url)
    time.sleep(1)

    # Find and click Quick apply
    result = js_click("Quick apply")
    print(f"  QA button: {result}")
    time.sleep(2)

    # Check if resume needs to be selected
    text = evaluate("document.body.innerText") or ""

    for attempt in range(5):
        text = evaluate("document.body.innerText") or ""

        if "Select a resumé" in text or "Please select a resumé" in text:
            print("  Selecting resume...")
            # Click the dropdown
            js_click("Select a resumé")
            time.sleep(1)
            # Pick latest
            js_click("Sean Cheong Software Engineer.pdf")
            print("  Resume selected")
            time.sleep(1.5)
            continue

        if "Resumé attached" in text and "Continue" in text:
            print("  Clicking Continue on docs step...")
            js_click("Continue")
            time.sleep(2)
            continue

        if "Review and submit" in text or "Update SEEK Profile" in text:
            if "Continue" in text:
                print("  Clicking Continue on profile step...")
                js_click("Continue")
                time.sleep(2)
                continue

        if "Submit application" in text.lower():
            print("  Found Submit button!")
            # Scroll down to ensure it's visible
            evaluate("window.scrollTo(0, document.body.scrollHeight)")
            time.sleep(0.5)
            result = js_click("Submit application")
            print(f"  Submit: {result}")
            time.sleep(3)

            # Verify
            text = evaluate("document.body.innerText") or ""
            if "applied" in text.lower():
                print(f"  ✅ SUBMITTED: {title}")
                return True
            else:
                print(f"  ⚠️  Clicked submit but may need check")
                return True

        # Check for error / already applied
        if "You applied" in text or "already applied" in text.lower():
            print(f"  ⏭️  Already applied to this one")
            return True

        print(f"  State: {text[300:600]}")
        break

    return False

# Jobs to process
jobs = [
    ("Junior Systems Engineer @ NSW Land Registry Services", "https://au.seek.com/job/92590790"),
    ("Cloud Support Engineer @ Networx Australia", "https://au.seek.com/job/92712961"),
    ("Technical Support Engineer @ Hyve Managed Hosting", "https://au.seek.com/job/92638587"),
    ("Level 1 Support Engineer @ Arxis Group (Graduate)", "https://au.seek.com/job/92747198"),
]

results = []
for title, url in jobs:
    success = do_quick_apply(title, url)
    results.append((title, "✅ Submitted" if success else "❌ Failed"))

print("\n\n=== FINAL RESULTS ===")
for r in results:
    print(f"  {r[0]}: {r[1]}")
