{"content":"#!/usr/bin/env python3
"""Quick Apply via SEEK - handles forms, questions, and submission."""
import json, urllib.request, time, re, sys

API = "http://127.0.0.1:3099"

def evaluate(expression):
    data = json.dumps({"expression": expression}).encode()
    req = urllib.request.Request(f"{API}/evaluate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    resp = json.loads(urllib.request.urlopen(req, timeout=15).read())
    return resp.get("result")

def navigate(url):
    data = json.dumps({"url": url}).encode()
    req = urllib.request.Request(f"{API}/navigate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    urllib.request.urlopen(req)
    time.sleep(3)

def click_continue():
    """Click the continue button regardless of zero-width chars."""
    return evaluate("""
    (() => {
        const btn = document.querySelector('button[data-testid="continue-button"]');
        if (btn) { btn.scrollIntoView({block: 'center'}); btn.click(); return 'clicked'; }
        // Fallback: find any button whose text contains Continue
        const btns = document.querySelectorAll('button');
        for (const b of btns) {
            if (b.textContent.includes('Continue')) {
                b.scrollIntoView({block: 'center'}); b.click(); return 'clicked_fuzzy';
            }
        }
        return 'none';
    })()
    """)

def do_quick_apply(title, url):
    print(f"\n{'='*70}")
    print(f"APPLYING: {title}")
    print(f"{'='*70}")

    navigate(url)
    time.sleep(1)

    # Step 1: Click Quick Apply button
    r = evaluate("""
    (() => {
        const btns = document.querySelectorAll('button, a');
        for (const b of btns) {
            if (b.textContent.trim() === 'Quick apply') {
                b.scrollIntoView({block: 'center'}); b.click(); return 'clicked';
            }
        }
        return 'not_found';
    })()
    """)
    print(f"  Quick apply: {r}")
    time.sleep(3)

    # Step 2: Select resume from dropdown
    r = evaluate("""
    (() => {
        const selects = document.querySelectorAll('select');
        for (const s of selects) {
            if (s.id && s.options.length > 1) {
                // Pick first non-empty option
                for (const o of s.options) {
                    if (o.value && o.value !== '') {
                        s.value = o.value;
                        s.dispatchEvent(new Event('change', {bubbles: true}));
                        return 'selected: ' + o.text.trim();
                    }
                }
            }
        }
        return 'no_select';
    })()
    """)
    print(f"  Resume: {r}")
    time.sleep(1)

    # Step 3: Click through forms (up to 8 steps max)
    for step in range(8):
        text = evaluate("document.body.innerText") or ""

        # Check if we should fill employer questions
        selects_pending = evaluate("""
        (() => {
            const selects = document.querySelectorAll('select');
            const pending = [];
            for (const s of selects) {
                if (!s.value || s.value === '') {
                    const label = document.querySelector('label[for="' + s.id + '"]');
                    const text = label ? label.textContent.trim() : s.name;
                    if (s.options.length > 1) {
                        // Select first real option
                        for (const o of s.options) {
                            if (o.value && o.value !== '') {
                                s.value = o.value;
                                s.dispatchEvent(new Event('change', {bubbles: true}));
                                pending.push('filled: ' + text.slice(0, 40));
                                break;
                            }
                        }
                    }
                }
            }
            return JSON.stringify(pending);
        })()
        """)
        if selects_pending and selects_pending != '[]':
            print(f"  Filled form fields: {selects_pending[:200]}")
            time.sleep(0.5)

        # Try to click Continue
        r = click_continue()
        time.sleep(2)

        # Check what happened
        text = evaluate("document.body.innerText") or ""

        if "applied" in text.lower():
            print(f"  ✅ SUBMITTED: {title}")
            return True

        if "Submit application" in text:
            print("  📋 At Submit step!")
            evaluate("window.scrollTo(0, document.body.scrollHeight)")
            time.sleep(0.5)
            r2 = evaluate("""
            (() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    if (b.textContent.includes('Submit application')) {
                        b.scrollIntoView({block: 'center'}); b.click(); return 'submitted';
                    }
                }
                return 'no_submit_btn';
            })()
            """)
            print(f"  Submit: {r2}")
            time.sleep(3)
            text = evaluate("document.body.innerText") or ""
            if "applied" in text.lower():
                print(f"  ✅ SUBMITTED: {title}")
                return True

        if r == 'none':
            print(f"  ⚠️ No more Continue buttons at step {step+1}")
            break

    print(f"  ❌ FAILED: {title}")
    return False


jobs = [
    ("Junior Systems Engineer @ NSW Land Registry Services", "https://au.seek.com/job/92590790"),
    ("Cloud Support Engineer @ Networx Australia", "https://au.seek.com/job/92712961"),
    ("Technical Support Engineer @ Hyve Managed Hosting ($80-95K)", "https://au.seek.com/job/92638587"),
    ("Level 1 Support Engineer @ Arxis Group - Graduate ($60-80K)", "https://au.seek.com/job/92747198"),
]

results = []
for title, url in jobs:
    try:
        ok = do_quick_apply(title, url)
        results.append((title, "✅" if ok else "❌"))
    except Exception as e:
        print(f"\n  ❌ ERROR: {e}")
        results.append((title, "❌"))

print("\n\n" + "="*70)
print("FINAL RESULTS")
print("="*70)
for title, status in results:
    print(f"  {status} {title}")
","path":"/tmp/batch_apply2.py"}

