{"content":"#!/usr/bin/env python3
"""Quickly check promising jobs for Quick Apply."""
import json, urllib.request, time

API = "http://127.0.0.1:3099"

def evaluate(expression):
    data = json.dumps({"expression": expression}).encode()
    req = urllib.request.Request(f"{API}/evaluate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    resp = json.loads(urllib.request.urlopen(req, timeout=15).read())
    return resp.get("result")

def navigate(url):
    data = json.dumps({"url": url}).encode()
    req = urllib.request.Request(f"{API}/navigate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    urllib.request.urlopen(req, timeout=10)
    time.sleep(2)

def check_and_apply(job):
    title, url = job['title'], job['url']
    navigate(url)

    text = evaluate("document.body.innerText") or ""
    if "You applied" in text:
        return ("already", None)

    # Check for QA
    has_qa = evaluate("""
    (() => {
        const btns = document.querySelectorAll('button, a');
        for (const b of btns) {
            if (b.textContent.trim() === 'Quick apply') return true;
        }
        return false;
    })()
    """)

    if not has_qa:
        return ("no_qa", None)

    print(f"  ➡️  QA: {title[:50]}")

    # Click QA
    evaluate("""
    (() => {
        const btns = document.querySelectorAll('button, a');
        for (const b of btns) {
            if (b.textContent.trim() === 'Quick apply') {
                b.scrollIntoView({block: 'center'}); b.click(); return;
            }
        }
    })()
    """)
    time.sleep(3)

    # Handle resume select
    evaluate("""
    (() => {
        const s = document.querySelector('select[data-testid="select-input"]');
        if (s) {
            if (s.value && s.value !== '') {
                s.dispatchEvent(new Event('change', {bubbles: true}));
            } else {
                for (const o of s.options) {
                    if (o.value && o.value !== '') { s.value = o.value; s.dispatchEvent(new Event('change', {bubbles: true})); break; }
                }
            }
        }
    })()
    """)
    time.sleep(1)

    # Click through all steps
    for step in range(10):
        text = evaluate("document.body.innerText") or ""
        if "applied" in text.lower():
            return ("applied", title)
        if "Submit application" in text:
            evaluate("window.scrollTo(0, document.body.scrollHeight)")
            time.sleep(0.5)
            evaluate("""
            (() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    if (b.textContent.includes('Submit application')) {
                        b.scrollIntoView({block: 'center'}); b.click(); return;
                    }
                }
            })()
            """)
            time.sleep(3)
            text = evaluate("document.body.innerText") or ""
            if "applied" in text.lower():
                return ("applied", title)
            return ("failed", title)

        # Fill selects
        evaluate("""
        (() => {
            const selects = document.querySelectorAll('select');
            for (const s of selects) {
                if ((!s.value || s.value === '') && s.options.length > 1) {
                    for (const o of s.options) {
                        if (o.value && o.value !== '') { s.value = o.value; s.dispatchEvent(new Event('change', {bubbles: true})); break; }
                    }
                }
            }
        })()
        """)

        r = evaluate("""
        (() => {
            const btn = document.querySelector('button[data-testid="continue-button"]');
            if (btn) { btn.scrollIntoView({block: 'center'}); btn.click(); return 'c'; }
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const t = b.textContent.replace(/[\\u200B-\\u200D\\uFEFF\\u2060]/g, '').trim();
                if (t === 'Continue') { b.scrollIntoView({block: 'center'}); b.click(); return 'f'; }
            }
            return 'n';
        })()
        """)
        if r == 'n':
            return ("stuck", title)
        time.sleep(2)

    return ("timeout", title)

# New promising roles to check
jobs_to_check = [
    {"title": "AWS Cloud Engineer", "url": "https://au.seek.com/job/92656803"},
    {"title": "Cloud Engineer", "url": "https://au.seek.com/job/92576546"},
    {"title": "Azure DevSecOps Engineer", "url": "https://au.seek.com/job/92361922"},
    {"title": "Junior Java Engineer", "url": "https://au.seek.com/job/92590212"},
    {"title": "Junior Digital Solutions Engineer", "url": "https://au.seek.com/job/92624583"},
    {"title": "Cloud Platform Engineer", "url": "https://au.seek.com/job/92265824"},
    {"title": "Platform Support Engineer", "url": "https://au.seek.com/job/92463112"},
    {"title": "Junior Full-Stack Software Engineer", "url": "https://au.seek.com/job/92678891"},
    {"title": "Cloud Engineer", "url": "https://au.seek.com/job/92679304"},
]

results = {"applied": [], "no_qa": [], "already": [], "failed": [], "stuck": []}
for job in jobs_to_check:
    try:
        status, title = check_and_apply(job)
        results[status].append(job["title"])
        icon = {"applied": "✅", "no_qa": "❌", "already": "⏭️", "failed": "⚠️", "stuck": "🔴"}[status]
        print(f"  {icon} {job['title']}: {status}")
    except Exception as e:
        print(f"  ❌ Error on {job['title']}: {e}")
        results["failed"].append(job["title"])

print(f"\n\n=== RESULTS ===")
for k, v in results.items():
    print(f"  {k}: {len(v)}")
    for t in v:
        print(f"    - {t}")
