"""Advanced Quick Apply - handles textareas, selects, and privacy checkboxes."""
import json, urllib.request, time

API = "http://127.0.0.1:3099"

def evaluate(expression):
    data = json.dumps({"expression": expression}).encode()
    req = urllib.request.Request(f"{API}/evaluate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    resp = json.loads(urllib.request.urlopen(req, timeout=15).read())
    return resp.get("result")

def navigate(url):
    data = json.dumps({"url": url}).encode()
    req = urllib.request.Request(f"{API}/navigate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    urllib.request.urlopen(req, timeout=10)
    time.sleep(4)

def fill_all_fields():
    """Fill all empty form fields - textareas with native setter, selects with value."""
    evaluate("""
    (() => {
        // Textareas - use native value setter for React
        document.querySelectorAll('textarea').forEach(ta => {
            if (!ta.value) {
                const nativeSetter = Object.getOwnPropertyDescriptor(
                    window.HTMLTextAreaElement.prototype, 'value'
                ).set;
                nativeSetter.call(ta, 'Yes');
                ta.dispatchEvent(new Event('input', {bubbles: true}));
                ta.dispatchEvent(new Event('change', {bubbles: true}));
            }
        });
        // Selects
        document.querySelectorAll('select').forEach(s => {
            if ((!s.value || s.value === '') && s.options.length > 1) {
                for (const o of s.options) {
                    if (o.value && o.value !== '') { 
                        s.value = o.value; 
                        s.dispatchEvent(new Event('change', {bubbles: true})); 
                        break; 
                    }
                }
            }
        });
        // Checkboxes (privacy policy etc)
        document.querySelectorAll('input[type="checkbox"]').forEach(cb => {
            if (!cb.checked) {
                cb.checked = true;
                cb.dispatchEvent(new Event('change', {bubbles: true}));
                cb.dispatchEvent(new Event('click', {bubbles: true}));
            }
        });
    })()
    """)

def apply_flow():
    fill_all_fields()
    time.sleep(1)

    for step in range(12):
        text = evaluate("document.body.innerText") or ""
        if "applied" in text.lower():
            return True
        if "Submit application" in text:
            evaluate("window.scrollTo(0, document.body.scrollHeight)")
            time.sleep(0.5)
            # Ensure all checkboxes checked
            evaluate("""
            (() => {
                document.querySelectorAll('input[type="checkbox"]').forEach(cb => {
                    if (!cb.checked) { cb.checked = true; cb.dispatchEvent(new Event('change', {bubbles: true})); }
                });
            })()
            """)
            time.sleep(0.5)
            evaluate("""
            (() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    if (b.textContent.includes('Submit application')) {
                        b.scrollIntoView({block: 'center'}); b.click(); return;
                    }
                }
            })()
            """)
            time.sleep(3)
            text = evaluate("document.body.innerText") or ""
            return "applied" in text.lower()

        fill_all_fields()

        r = evaluate("""
        (() => {
            const btn = document.querySelector('button[data-testid="continue-button"]');
            if (btn) { btn.scrollIntoView({block: 'center'}); btn.click(); return 'c'; }
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const t = b.textContent.replace(/[\\u200B-\\u200D\\uFEFF\\u2060]/g, '').trim();
                if (t === 'Continue') { b.scrollIntoView({block: 'center'}); b.click(); return 'f'; }
            }
            return 'n';
        })()
        """)
        if r == 'n':
            return False
        time.sleep(2)
    return False

# Try the 2 remaining failed jobs
jobs = [
    ("Cloud Engineer @ Shield Recruitment", "https://au.seek.com/job/92576546"),
    ("Cloud Platform Engineer", "https://au.seek.com/job/92265824"),
]

for title, url in jobs:
    print(f"\n=== {title} ===")
    navigate(url)

    # Click QA
    has_qa = evaluate("""
    (() => {
        const btns = document.querySelectorAll('button, a');
        for (const b of btns) {
            if (b.textContent.trim() === 'Quick apply') return true;
        }
        return false;
    })()
    """)
    if not has_qa:
        print(f"  ❌ No QA available")
        continue

    evaluate("""
    (() => {
        const btns = document.querySelectorAll('button, a');
        for (const b of btns) {
            if (b.textContent.trim() === 'Quick apply') {
                b.scrollIntoView({block: 'center'}); b.click(); return;
