"""Apply with full radio/checkbox/textarea/select support."""
import json, urllib.request, time

API = "http://127.0.0.1:3099"

def evaluate(expression):
    data = json.dumps({"expression": expression}).encode()
    req = urllib.request.Request(f"{API}/evaluate", data=data,
        headers={"Content-Type": "application/json"}, method="POST")
    resp = json.loads(urllib.request.urlopen(req, timeout=15).read())
    return resp.get("result")

def navigate(url):
    data = json.dumps({"url": url}).encode()
    urllib.request.urlopen(urllib.request.Request(f"{API}/navigate", data=data,
        headers={"Content-Type": "application/json"}, method="POST"), timeout=10)
    time.sleep(4)

def fill_all():
    evaluate("""
    (() => {
        // Textareas
        document.querySelectorAll('textarea').forEach(ta => {
            if (!ta.value) {
                const ns = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
                ns.call(ta, 'Yes'); ta.dispatchEvent(new Event('input', {bubbles: true}));
            }
        });
        // Selects
        document.querySelectorAll('select').forEach(s => {
            if ((!s.value || s.value === '') && s.options.length > 1) {
                for (const o of s.options) { if (o.value && o.value !== '') { s.value = o.value; s.dispatchEvent(new Event('change', {bubbles: true})); break; } }
            }
        });
        // Radio groups - click label for last option if none checked
        const groups = {};
        document.querySelectorAll('input[type="radio"]').forEach(r => {
            if (r.name) { if (!groups[r.name]) groups[r.name] = []; groups[r.name].push(r); }
        });
        for (const radios of Object.values(groups)) {
            if (!radios.some(r => r.checked)) {
                const last = radios[radios.length - 1];
                const label = document.querySelector('label[for="' + last.id + '"]');
                if (label) label.click();
                else { last.checked = true; last.dispatchEvent(new Event('change', {bubbles: true})); }
            }
        }
        // Checkboxes
        document.querySelectorAll('input[type="checkbox"]').forEach(cb => {
            if (!cb.checked) {
                const ns = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'checked').set;
                ns.call(cb, true);
                cb.dispatchEvent(new Event('change', {bubbles: true}));
            }
        });
    })()
    """)

def step_through():
    for step in range(12):
        text = evaluate("document.body.innerText") or ""
        if "applied" in text.lower(): return True
        if "Submit application" in text:
            evaluate("window.scrollTo(0, document.body.scrollHeight)"); time.sleep(0.5)
            fill_all()
            time.sleep(0.5)
            evaluate("""
            (() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    if (b.textContent.includes('Submit application')) {
                        b.scrollIntoView({block: 'center'}); b.click(); return;
                    }
                }
            })()
            """)
            time.sleep(3)
            text = evaluate("document.body.innerText") or ""
            return "applied" in text.lower()

