                if (t === 'Continue') { b.scrollIntoView({block: 'center'}); b.click(); return 'f'; }
            }
            return 'n';
        })()
        """)
        if r == 'n': return False
        time.sleep(2)
    return False

# Cloud Platform Engineer
print("=== Cloud Platform Engineer ===")
navigate("https://au.seek.com/job/92265824")

# Check QA
has_qa = evaluate("""
(() => {
    const btns = document.querySelectorAll('button, a');
